export const adminDashboardDesign = {
  colors: {
    background: "bg-gray-950",
    sidebar: "bg-gray-900",
    card: "bg-gray-800",
    textPrimary: "text-white",
    textSecondary: "text-gray-400",
    accent: "text-indigo-400",
  },

  layout: {
    container: "min-h-screen flex",
    sidebar: "w-64 hidden md:flex flex-col p-6 space-y-6",
    content: "flex-1 p-6 md:p-10",
    grid: "grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-6",
    card: "p-6 rounded-2xl shadow-lg",
  },

  animation: {
    container: {
      initial: { opacity: 0 },
      animate: { opacity: 1 },
      transition: { duration: 0.5 },
    },
    card: {
      whileHover: { scale: 1.05 },
      transition: { type: "spring", stiffness: 300 },
    },
  },
};
